/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWArea-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'ARENOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &AreNom1.FromString(&GridStateDynamicFilter.Value) If not &AreNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "WWP_FilterLike") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "WWP_FilterContains") Case &DynamicFiltersOperator1 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Começa com") Case &DynamicFiltersOperator1 = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AreNom1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'ARENOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &AreNom2.FromString(&GridStateDynamicFilter.Value) If not &AreNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "WWP_FilterLike") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "WWP_FilterContains") Case &DynamicFiltersOperator2 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Começa com") Case &DynamicFiltersOperator2 = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AreNom2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'ARENOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &AreNom3.FromString(&GridStateDynamicFilter.Value) If not &AreNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "WWP_FilterLike") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "WWP_FilterContains") Case &DynamicFiltersOperator3 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Começa com") Case &DynamicFiltersOperator3 = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AreNom3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Área" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Observação"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod AreCod when &OrderedBy = 1 order AreCod when &OrderedBy = 2 AND &OrderedDsc = False order (AreCod) when &OrderedBy = 2 AND &OrderedDsc = True order AreNom when &OrderedBy = 3 AND &OrderedDsc = False order (AreNom) when &OrderedBy = 3 AND &OrderedDsc = True order AreSts when &OrderedBy = 4 AND &OrderedDsc = False order (AreSts) when &OrderedBy = 4 AND &OrderedDsc = True order AreObs when &OrderedBy = 5 AND &OrderedDsc = False order (AreObs) when &OrderedBy = 5 AND &OrderedDsc = True
using DSWWArea(&DynamicFiltersSelector1, &DynamicFiltersOperator1, &AreNom1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &DynamicFiltersOperator2 , &AreNom2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3, &AreNom3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = AreCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(AreNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = AreSts.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(AreObs)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWAreaGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWAreaGridState")) Else &GridState.FromXml(&Session.Get(!"WWAreaGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

